#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[6], t[6];
        scanf("%5s %5s", s, t);
        char ans[6];
        for (int i = 0; i < 5; ++i) {
            ans[i] = (s[i] == t[i]) ? 'G' : 'B';
        }
        ans[5] = '\0';
        printf("%s\n", ans);
    }
    return 0;
}

